32	        const npy_packed_static_string *ps1 = (npy_packed_static_string *)in1;     \
33	        npy_static_string s1 = {0, NULL};                                          \
34	        int s1_isnull = NpyString_load(s1allocator, ps1, &s1);                     \
35	        const npy_packed_static_string *ps2 = (npy_packed_static_string *)in2;     \
