45	static NPY_CASTING
46	multiply_resolve_descriptors(
47	        struct PyArrayMethodObject_tag *NPY_UNUSED(method),
48	        PyArray_DTypeMeta *const dtypes[], PyArray_Descr *const given_descrs[],
49	        PyArray_Descr *loop_descrs[], npy_intp *NPY_UNUSED(view_offset))
50	{
51	    PyArray_Descr *ldescr = given_descrs[0];
52	    PyArray_Descr *rdescr = given_descrs[1];
53	    PyArray_StringDTypeObject *odescr = NULL;
54	    PyArray_Descr *out_descr = NULL;
55	
56	    if (dtypes[0] == &PyArray_StringDType) {
57	        odescr = (PyArray_StringDTypeObject *)ldescr;
58	    }
59	    else {
60	        odescr = (PyArray_StringDTypeObject *)rdescr;
61	    }
62	
63	    if (given_descrs[2] == NULL) {
64	        out_descr = (PyArray_Descr *)new_stringdtype_instance(
65	                odescr->na_object, odescr->coerce);
66	        if (out_descr == NULL) {
67	            return (NPY_CASTING)-1;
68	        }
69	    }
70	    else {
71	        Py_INCREF(given_descrs[2]);
72	        out_descr = given_descrs[2];
73	    }
74	
75	    Py_INCREF(ldescr);
76	    loop_descrs[0] = ldescr;
77	    Py_INCREF(rdescr);
78	    loop_descrs[1] = rdescr;
79	    loop_descrs[2] = out_descr;
80	
81	    return NPY_NO_CASTING;
82	}
