84	template <typename T>
85	static int multiply_loop_core(
86	        npy_intp N, char *sin, char *iin, char *out,
87	        npy_intp s_stride, npy_intp i_stride, npy_intp o_stride,
88	        PyArray_StringDTypeObject *idescr, PyArray_StringDTypeObject *odescr)
89	{
90	    PyArray_Descr *descrs[2] =
91	            {(PyArray_Descr *)idescr, (PyArray_Descr *)odescr};
92	    npy_string_allocator *allocators[2] = {};
93	    NpyString_acquire_allocators(2, descrs, allocators);
94	    npy_string_allocator *iallocator = allocators[0];
95	    npy_string_allocator *oallocator = allocators[1];
96	    int has_null = idescr->na_object != NULL;
97	    int has_nan_na = idescr->has_nan_na;
98	    int has_string_na = idescr->has_string_na;
99	    const npy_static_string *default_string = &idescr->default_string;
100	
101	    while (N--) {
102	        const npy_packed_static_string *ips =
103	                (npy_packed_static_string *)sin;
104	        npy_static_string is = {0, NULL};
105	        npy_packed_static_string *ops = (npy_packed_static_string *)out;
106	        int is_isnull = NpyString_load(iallocator, ips, &is);
107	        if (is_isnull == -1) {
108	            npy_gil_error(PyExc_MemoryError,
109	                      "Failed to load string in multiply");
110	            goto fail;
111	        }
112	        else if (is_isnull) {
113	            if (has_nan_na) {
114	                if (NpyString_pack_null(oallocator, ops) < 0) {
115	                    npy_gil_error(PyExc_MemoryError,
116	                              "Failed to deallocate string in multiply");
117	                    goto fail;
118	                }
119	
120	                sin += s_stride;
121	                iin += i_stride;
122	                out += o_stride;
123	                continue;
124	            }
125	            else if (has_string_na || !has_null) {
126	                is = *(npy_static_string *)default_string;
127	            }
128	            else {
129	                npy_gil_error(PyExc_TypeError,
130	                          "Cannot multiply null that is not a nan-like "
131	                          "value");
132	                goto fail;
133	            }
134	        }
135	        T factor = *(T *)iin;
136	        size_t cursize = is.size;
137	        size_t newsize;
138	        int overflowed = npy_mul_with_overflow_size_t(
139	                &newsize, cursize, factor);
140	        if (overflowed || newsize > PY_SSIZE_T_MAX) {
141	            npy_gil_error(PyExc_OverflowError,
142	                      "Overflow encountered in string multiply");
143	            goto fail;
144	        }
145	
146	        char *buf = NULL;
147	        npy_static_string os = {0, NULL};
148	        // in-place
149	        if (descrs[0] == descrs[1]) {
150	            buf = (char *)PyMem_RawMalloc(newsize);
151	            if (buf == NULL) {
152	                npy_gil_error(PyExc_MemoryError,
153	                              "Failed to allocate string in multiply");
154	                goto fail;
155	            }
156	        }
157	        else {
158	            if (load_new_string(
159	                        ops, &os, newsize,
160	                        oallocator, "multiply") == -1) {
161	                goto fail;
162	            }
163	            /* explicitly discard const; initializing new buffer */
164	            buf = (char *)os.buf;
165	        }
166	
167	        for (size_t i = 0; i < (size_t)factor; i++) {
168	            /* multiply can't overflow because cursize * factor */
169	            /* has already been checked and doesn't overflow */
170	            memcpy((char *)buf + i * cursize, is.buf, cursize);
171	        }
172	
173	        // clean up temp buffer for in-place operations
174	        if (descrs[0] == descrs[1]) {
175	            if (NpyString_pack(oallocator, ops, buf, newsize) < 0) {
176	                npy_gil_error(PyExc_MemoryError,
177	                              "Failed to pack string in multiply");
178	                goto fail;
179	            }
180	
181	            PyMem_RawFree(buf);
182	        }
183	
184	        sin += s_stride;
185	        iin += i_stride;
186	        out += o_stride;
187	    }
188	    NpyString_release_allocators(2, allocators);
189	    return 0;
190	
191	fail:
192	    NpyString_release_allocators(2, allocators);
193	    return -1;
194	}
