198	        PyArrayMethod_Context *context, char *const data[],
199	        npy_intp const dimensions[], npy_intp const strides[],
200	        NpyAuxData *NPY_UNUSED(auxdata))
201	{
202	    PyArray_StringDTypeObject *idescr =
203	            (PyArray_StringDTypeObject *)context->descriptors[0];
204	    PyArray_StringDTypeObject *odescr =
205	            (PyArray_StringDTypeObject *)context->descriptors[2];
