282	static int
283	add_strided_loop(PyArrayMethod_Context *context, char *const data[],
284	                 npy_intp const dimensions[], npy_intp const strides[],
285	                 NpyAuxData *NPY_UNUSED(auxdata))
286	{
287	    PyArray_StringDTypeObject *s1descr = (PyArray_StringDTypeObject *)context->descriptors[0];
288	    PyArray_StringDTypeObject *s2descr = (PyArray_StringDTypeObject *)context->descriptors[1];
289	    PyArray_StringDTypeObject *odescr = (PyArray_StringDTypeObject *)context->descriptors[2];
290	    PyArray_StringDTypeObject *nadescr = stringdtype_effective_na_descr(
291	            context->method->nin, context->descriptors);
292	    int has_null = nadescr->na_object != NULL;
293	    int has_nan_na = nadescr->has_nan_na;
294	    int has_string_na = nadescr->has_string_na;
295	    const npy_static_string *default_string = &nadescr->default_string;
296	    npy_intp N = dimensions[0];
297	    char *in1 = data[0];
298	    char *in2 = data[1];
299	    char *out = data[2];
300	    npy_intp in1_stride = strides[0];
301	    npy_intp in2_stride = strides[1];
302	    npy_intp out_stride = strides[2];
303	
304	    npy_string_allocator *allocators[3] = {};
305	    NpyString_acquire_allocators(3, context->descriptors, allocators);
306	    npy_string_allocator *s1allocator = allocators[0];
307	    npy_string_allocator *s2allocator = allocators[1];
308	    npy_string_allocator *oallocator = allocators[2];
309	
310	    while (N--) {
311	        LOAD_TWO_INPUT_STRINGS("add")
312	        char *buf = NULL;
313	        npy_static_string os = {0, NULL};
314	        size_t newsize = 0;
315	        npy_packed_static_string *ops = (npy_packed_static_string *)out;
316	        if (NPY_UNLIKELY(s1_isnull || s2_isnull)) {
317	            if (has_nan_na) {
318	                if (NpyString_pack_null(oallocator, ops) < 0) {
319	                    npy_gil_error(PyExc_MemoryError,
320	                                  "Failed to deallocate string in add");
321	                    goto fail;
322	                }
323	                goto next_step;
324	            }
325	            else if (has_string_na || !has_null) {
326	                if (s1_isnull) {
327	                    s1 = *default_string;
328	                }
329	                if (s2_isnull) {
330	                    s2 = *default_string;
331	                }
332	            }
333	            else {
334	                npy_gil_error(PyExc_ValueError,
335	                              "Cannot add null that is not a nan-like value");
336	                goto fail;
337	            }
338	        }
339	
340	        // check for overflow
341	        newsize = s1.size + s2.size;
342	        if (newsize < s1.size) {
343	            npy_gil_error(PyExc_MemoryError, "Failed to allocate string in add");
344	            goto fail;
345	        }
346	
347	        // in-place
348	        if (s1descr == odescr || s2descr == odescr) {
349	            buf = (char *)PyMem_RawMalloc(newsize);
350	
351	            if (buf == NULL) {
352	                npy_gil_error(PyExc_MemoryError,
353	                          "Failed to allocate string in add");
354	                goto fail;
355	            }
356	        }
357	        else {
358	            if (load_new_string(ops, &os, newsize, oallocator, "add") == -1) {
359	                goto fail;
360	            }
361	            // explicitly discard const; initializing new buffer
362	            buf = (char *)os.buf;
363	        }
364	
365	        memcpy(buf, s1.buf, s1.size);
366	        memcpy(buf + s1.size, s2.buf, s2.size);
367	
368	        // clean up temporary in-place buffer
369	        if (s1descr == odescr || s2descr == odescr) {
370	            if (NpyString_pack(oallocator, ops, buf, newsize) < 0) {
371	                npy_gil_error(PyExc_MemoryError,
372	                          "Failed to pack output string in add");
373	                goto fail;
374	            }
375	
376	            PyMem_RawFree(buf);
377	        }
378	
379	    next_step:
380	        in1 += in1_stride;
381	        in2 += in2_stride;
382	        out += out_stride;
383	    }
384	    NpyString_release_allocators(3, allocators);
385	    return 0;
386	
387	fail:
388	    NpyString_release_allocators(3, allocators);
389	    return -1;
390	}
