393	static int
394	minimum_maximum_strided_loop(PyArrayMethod_Context *context, char *const data[],
395	                     npy_intp const dimensions[], npy_intp const strides[],
396	                     NpyAuxData *NPY_UNUSED(auxdata))
397	{
398	    const char *ufunc_name = ((PyUFuncObject *)context->caller)->name;
399	    npy_bool invert = *(npy_bool *)context->method->static_data; // true for maximum
400	    PyArray_StringDTypeObject *in1_descr =
401	            ((PyArray_StringDTypeObject *)context->descriptors[0]);
402	    PyArray_StringDTypeObject *in2_descr =
403	            ((PyArray_StringDTypeObject *)context->descriptors[1]);
404	    npy_intp N = dimensions[0];
405	    char *in1 = data[0];
406	    char *in2 = data[1];
407	    char *out = data[2];
408	    npy_intp in1_stride = strides[0];
409	    npy_intp in2_stride = strides[1];
410	    npy_intp out_stride = strides[2];
411	
412	    npy_string_allocator *allocators[3] = {};
413	    NpyString_acquire_allocators(3, context->descriptors, allocators);
414	    npy_string_allocator *in1_allocator = allocators[0];
415	    npy_string_allocator *in2_allocator = allocators[1];
416	    npy_string_allocator *out_allocator = allocators[2];
417	
418	    while (N--) {
419	        const npy_packed_static_string *sin1 = (npy_packed_static_string *)in1;
420	        const npy_packed_static_string *sin2 = (npy_packed_static_string *)in2;
421	        npy_packed_static_string *sout = (npy_packed_static_string *)out;
422	        int cmp = _compare(in1, in2, in1_descr, in2_descr);
423	        if (cmp == 0 && (in1 == out || in2 == out)) {
424	            goto next_step;
425	        }
426	        if ((cmp < 0) ^ invert) {
427	            // if in and out are the same address, do nothing to avoid a
428	            // use-after-free
429	            if (in1 != out) {
430	                if (free_and_copy(in1_allocator, out_allocator, sin1, sout,
431	                                  ufunc_name) == -1) {
432	                    goto fail;
433	                }
434	            }
435	        }
436	        else {
437	            if (in2 != out) {
438	                if (free_and_copy(in2_allocator, out_allocator, sin2, sout,
439	                                  ufunc_name) == -1) {
440	                    goto fail;
441	                }
442	            }
443	        }
444	
445	      next_step:
446	        in1 += in1_stride;
447	        in2 += in2_stride;
448	        out += out_stride;
449	    }
450	
451	    NpyString_release_allocators(3, allocators);
452	    return 0;
453	
454	fail:
455	    NpyString_release_allocators(3, allocators);
456	    return -1;
457	}
