459	static int
460	string_comparison_strided_loop(PyArrayMethod_Context *context, char *const data[],
461	                            npy_intp const dimensions[],
462	                            npy_intp const strides[],
463	                            NpyAuxData *NPY_UNUSED(auxdata))
464	{
465	    const char *ufunc_name = ((PyUFuncObject *)context->caller)->name;
466	    npy_bool res_for_eq = ((npy_bool *)context->method->static_data)[0];
467	    npy_bool res_for_lt = ((npy_bool *)context->method->static_data)[1];
468	    npy_bool res_for_gt = ((npy_bool *)context->method->static_data)[2];
469	    npy_bool res_for_ne = !res_for_eq;
470	    npy_bool eq_or_ne = res_for_lt == res_for_gt;
471	    PyArray_StringDTypeObject *nadescr = stringdtype_effective_na_descr(
472	            context->method->nin, context->descriptors);
473	    int has_null = nadescr->na_object != NULL;
474	    int has_nan_na = nadescr->has_nan_na;
475	    int has_string_na = nadescr->has_string_na;
476	    const npy_static_string *default_string = &nadescr->default_string;
477	    npy_intp N = dimensions[0];
478	    char *in1 = data[0];
479	    char *in2 = data[1];
480	    npy_bool *out = (npy_bool *)data[2];
481	    npy_intp in1_stride = strides[0];
482	    npy_intp in2_stride = strides[1];
483	    npy_intp out_stride = strides[2];
484	
485	    npy_string_allocator *allocators[2] = {};
486	    NpyString_acquire_allocators(2, context->descriptors, allocators);
487	    npy_string_allocator *s1allocator = allocators[0];
488	    npy_string_allocator *s2allocator = allocators[1];
489	
490	    while (N--) {
491	        int cmp;
492	        LOAD_TWO_INPUT_STRINGS(ufunc_name);
493	        if (NPY_UNLIKELY(s1_isnull || s2_isnull)) {
494	            if (has_nan_na) {
495	                // s1 or s2 is NA
496	                *out = NPY_FALSE;
497	                goto next_step;
498	            }
499	            else if (has_null && !has_string_na) {
500	                if (eq_or_ne) {
501	                    if (s1_isnull && s2_isnull) {
502	                        *out = res_for_eq;
503	                    }
504	                    else {
505	                        *out = res_for_ne;
506	                    }
507	                }
508	                else {
509	                    npy_gil_error(PyExc_ValueError,
510	                                  "'%s' not supported for null values that are not "
511	                                  "nan-like or strings.", ufunc_name);
512	                    goto fail;
513	                }
514	            }
515	            else {
