1679	static int
1680	center_ljust_rjust_strided_loop(PyArrayMethod_Context *context,
1681	                                char *const data[],
1682	                                npy_intp const dimensions[],
1683	                                npy_intp const strides[],
1684	                                NpyAuxData *NPY_UNUSED(auxdata))
1685	{
1686	    PyArray_StringDTypeObject *nadescr = stringdtype_effective_na_descr(
1687	            context->method->nin, context->descriptors);
1688	    int has_null = nadescr->na_object != NULL;
1689	    int has_nan_na = nadescr->has_nan_na;
1690	    int has_string_na = nadescr->has_string_na;
1691	    const npy_static_string *default_string = &nadescr->default_string;
1692	    npy_intp N = dimensions[0];
1693	    char *in1 = data[0];
1694	    char *in2 = data[1];
1695	    char *in3 = data[2];
1696	    char *out = data[3];
1697	    npy_intp in1_stride = strides[0];
1698	    npy_intp in2_stride = strides[1];
1699	    npy_intp in3_stride = strides[2];
1700	    npy_intp out_stride = strides[3];
1701	
1702	    npy_string_allocator *allocators[4] = {};
1703	    NpyString_acquire_allocators(4, context->descriptors, allocators);
1704	    npy_string_allocator *s1allocator = allocators[0];
1705	    // allocators[1] is NULL
1706	    npy_string_allocator *s2allocator = allocators[2];
1707	    npy_string_allocator *oallocator = allocators[3];
1708	
1709	    JUSTPOSITION pos = *(JUSTPOSITION *)(context->method->static_data);
1710	    const char* ufunc_name = ((PyUFuncObject *)context->caller)->name;
1711	
1712	    while (N--) {
1713	        const npy_packed_static_string *ps1 = (npy_packed_static_string *)in1;
1714	        npy_static_string s1 = {0, NULL};
1715	        int s1_isnull = NpyString_load(s1allocator, ps1, &s1);
1716	        const npy_packed_static_string *ps2 = (npy_packed_static_string *)in3;
1717	        npy_static_string s2 = {0, NULL};
1718	        int s2_isnull = NpyString_load(s2allocator, ps2, &s2);
1719	        npy_static_string os = {0, NULL};
1720	        npy_packed_static_string *ops = (npy_packed_static_string *)out;
1721	        if (s1_isnull == -1 || s2_isnull == -1) {
1722	            npy_gil_error(PyExc_MemoryError, "Failed to load string in %s",
1723	                          ufunc_name);
1724	            goto fail;
1725	        }
1726	        if (NPY_UNLIKELY(s1_isnull || s2_isnull)) {
1727	            if (has_nan_na) {
1728	                if (NpyString_pack_null(oallocator, ops) < 0) {
1729	                    npy_gil_error(PyExc_MemoryError,
1730	                                  "Failed to deallocate string in %s",
1731	                                  ufunc_name);
1732	                    goto fail;
1733	                }
1734	                goto next_step;
1735	            }
1736	            else if (has_string_na || !has_null) {
1737	                if (s1_isnull) {
1738	                    s1 = *default_string;
1739	                }
1740	                if (s2_isnull) {
1741	                    s2 = *default_string;
1742	                }
1743	            }
1744	            else {
1745	                npy_gil_error(PyExc_ValueError,
1746	                              "Cannot %s null that is not a nan-like value",
1747	                              ufunc_name);
1748	                goto fail;
1749	            }
1750	        }
1751	        {
1752	            Buffer<ENCODING::UTF8> inbuf((char *)s1.buf, s1.size);
1753	            Buffer<ENCODING::UTF8> fill((char *)s2.buf, s2.size);
1754	
1755	            size_t num_codepoints = inbuf.num_codepoints();
1756	            npy_intp width = (npy_intp)*(npy_int64*)in2;
1757	
1758	            if ((npy_intp)num_codepoints > width) {
1759	                width = num_codepoints;
1760	            }
1761	
1762	            char *buf = NULL;
1763	            npy_intp newsize;
1764	            int overflowed = npy_mul_sizes_with_overflow(
1765	                    &(newsize),
1766	                    (npy_intp)num_bytes_for_utf8_character((unsigned char *)s2.buf),
1767	                    width - num_codepoints);
1768	            newsize += s1.size;
1769	
1770	            if (overflowed || newsize > PY_SSIZE_T_MAX) {
1771	                npy_gil_error(PyExc_OverflowError,
1772	                              "Overflow encountered in %s", ufunc_name);
1773	                goto fail;
1774	            }
1775	
1776	            if (context->descriptors[0] == context->descriptors[3]) {
1777	                // in-place
1778	                buf = (char *)PyMem_RawMalloc(newsize);
1779	                if (buf == NULL) {
1780	                    npy_gil_error(PyExc_MemoryError,
1781	                                  "Failed to allocate string in %s", ufunc_name);
1782	                    goto fail;
1783	                }
1784	            }
1785	            else {
1786	                if (load_new_string(ops, &os, newsize, oallocator, ufunc_name) < 0) {
1787	                    goto fail;
1788	                }
1789	                /* explicitly discard const; initializing new buffer */
1790	                buf = (char *)os.buf;
1791	            }
1792	
1793	            Buffer<ENCODING::UTF8> outbuf(buf, newsize);
1794	
1795	            npy_intp len = string_pad(inbuf, *(npy_int64*)in2, *fill, pos, outbuf);
1796	
1797	            if (len < 0) {
1798	                return -1;
1799	            }
1800	
1801	            // in-place operations need to clean up temp buffer
1802	            if (context->descriptors[0] == context->descriptors[3]) {
1803	                if (NpyString_pack(oallocator, ops, buf, newsize) < 0) {
1804	                    npy_gil_error(PyExc_MemoryError,
1805	                                  "Failed to pack string in %s", ufunc_name);
1806	                    goto fail;
1807	                }
1808	
1809	                PyMem_RawFree(buf);
1810	            }
1811	        }
1812	      next_step:
1813	
1814	        in1 += in1_stride;
1815	        in2 += in2_stride;
1816	        in3 += in3_stride;
1817	        out += out_stride;
1818	    }
1819	
1820	    NpyString_release_allocators(4, allocators);
1821	    return 0;
1822	
1823	 fail:
1824	    NpyString_release_allocators(4, allocators);
1825	    return -1;
1826	}
