1828	static int
1829	zfill_strided_loop(PyArrayMethod_Context *context,
1830	                   char *const data[], npy_intp const dimensions[],
1831	                   npy_intp const strides[], NpyAuxData *NPY_UNUSED(auxdata))
1832	{
1833	    PyArray_StringDTypeObject *idescr =
1834	            (PyArray_StringDTypeObject *)context->descriptors[0];
1835	    npy_intp N = dimensions[0];
1836	    char *in1 = data[0];
1837	    char *in2 = data[1];
1838	    char *out = data[2];
1839	    npy_intp in1_stride = strides[0];
1840	    npy_intp in2_stride = strides[1];
1841	    npy_intp out_stride = strides[2];
1842	
1843	    npy_string_allocator *allocators[3] = {};
1844	    NpyString_acquire_allocators(3, context->descriptors, allocators);
1845	    npy_string_allocator *iallocator = allocators[0];
1846	    // allocators[1] is NULL
1847	    npy_string_allocator *oallocator = allocators[2];
1848	    int has_null = idescr->na_object != NULL;
1849	    int has_nan_na = idescr->has_nan_na;
1850	    int has_string_na = idescr->has_string_na;
1851	    const npy_static_string *default_string = &idescr->default_string;
1852	
1853	    while (N--) {
1854	        npy_static_string is = {0, NULL};
1855	        const npy_packed_static_string *ips =
1856	                (npy_packed_static_string *)in1;
1857	        npy_static_string os = {0, NULL};
1858	        npy_packed_static_string *ops = (npy_packed_static_string *)out;
1859	        int is_isnull = NpyString_load(iallocator, ips, &is);
1860	        if (is_isnull == -1) {
1861	            npy_gil_error(PyExc_MemoryError,
1862	                          "Failed to load string in zfill");
1863	            goto fail;
1864	        }
1865	        else if (is_isnull) {
1866	            if (has_nan_na) {
1867	                if (NpyString_pack_null(oallocator, ops) < 0) {
1868	                    npy_gil_error(PyExc_MemoryError,
1869	                                  "Failed to deallocate string in zfill");
1870	                    goto fail;
1871	                }
1872	
1873	                goto next_step;
1874	            }
1875	            else if (has_string_na || !has_null) {
1876	                is = *(npy_static_string *)default_string;
1877	            }
1878	            else {
1879	                npy_gil_error(PyExc_TypeError,
1880	                          "Cannot zfill null string that is not a nan-like "
1881	                          "value");
1882	                goto fail;
1883	            }
1884	        }
1885	        {
1886	            Buffer<ENCODING::UTF8> inbuf((char *)is.buf, is.size);
1887	            size_t in_codepoints = inbuf.num_codepoints();
1888	            npy_intp width = (npy_intp)*(npy_int64*)in2;
1889	            if ((npy_intp)in_codepoints > width) {
1890	                width = in_codepoints;
1891	            }
1892	            // number of leading one-byte characters plus the size of the
1893	            // original string
1894	            size_t outsize = (width - in_codepoints) + is.size;
1895	            char *buf = NULL;
1896	            if (context->descriptors[0] == context->descriptors[2]) {
1897	                // in-place
1898	                buf = (char *)PyMem_RawMalloc(outsize);
1899	                if (buf == NULL) {
1900	                    npy_gil_error(PyExc_MemoryError,
1901	                                  "Failed to allocate string in zfill");
1902	                    goto fail;
1903	                }
1904	            }
1905	            else {
1906	                if (load_new_string(ops, &os, outsize, oallocator, "zfill") < 0) {
1907	                    goto fail;
1908	                }
1909	                /* explicitly discard const; initializing new buffer */
1910	                buf = (char *)os.buf;
1911	            }
1912	
1913	            Buffer<ENCODING::UTF8> outbuf(buf, outsize);
1914	            if (string_zfill(inbuf, (npy_int64)width, outbuf) < 0) {
1915	                goto fail;
1916	            }
1917	
1918	            // in-place operations need to clean up temp buffer
1919	            if (context->descriptors[0] == context->descriptors[2]) {
1920	                if (NpyString_pack(oallocator, ops, buf, outsize) < 0) {
1921	                    npy_gil_error(PyExc_MemoryError,
1922	                                  "Failed to pack string in zfill");
1923	                    goto fail;
1924	                }
1925	
1926	                PyMem_RawFree(buf);
1927	            }
1928	
1929	        }
1930	
1931	      next_step:
1932	
1933	        in1 += in1_stride;
1934	        in2 += in2_stride;
1935	        out += out_stride;
1936	    }
1937	
1938	    NpyString_release_allocators(3, allocators);
1939	    return 0;
1940	
1941	fail:
1942	    NpyString_release_allocators(3, allocators);
1943	    return -1;
1944	}
