1948	string_partition_resolve_descriptors(
1949	        PyArrayMethodObject *self,
1950	        PyArray_DTypeMeta *const NPY_UNUSED(dtypes[5]),
1951	        PyArray_Descr *const given_descrs[5],
1952	        PyArray_Descr *loop_descrs[5],
1953	        npy_intp *NPY_UNUSED(view_offset))
1954	{
1955	    if (given_descrs[2] || given_descrs[3] || given_descrs[4]) {
