1959	    }
1960	
1961	    PyObject *out_na_object = NULL;
1962	    int out_coerce = 1;
1963	
1964	    if (stringdtype_common_na_coerce(self->nin, given_descrs,
1965	                                     &out_na_object, &out_coerce) == -1) {
1966	        return (NPY_CASTING)-1;
1967	    }
1968	
1969	    Py_INCREF(given_descrs[0]);
1970	    loop_descrs[0] = given_descrs[0];
1971	    Py_INCREF(given_descrs[1]);
1972	    loop_descrs[1] = given_descrs[1];
1973	
1974	    for (int i=2; i<5; i++) {
1975	        loop_descrs[i] = (PyArray_Descr *)new_stringdtype_instance(
