1985	NPY_NO_EXPORT int
1986	string_partition_strided_loop(
1987	        PyArrayMethod_Context *context,
1988	        char *const data[],
1989	        npy_intp const dimensions[],
1990	        npy_intp const strides[],
1991	        NpyAuxData *NPY_UNUSED(auxdata))
1992	{
1993	    STARTPOSITION startposition = *(STARTPOSITION *)(context->method->static_data);
1994	    int fastsearch_direction =
1995	            startposition == STARTPOSITION::FRONT ? FAST_SEARCH : FAST_RSEARCH;
1996	
1997	    npy_intp N = dimensions[0];
1998	
1999	    char *in1 = data[0];
2000	    char *in2 = data[1];
2001	    char *out1 = data[2];
2002	    char *out2 = data[3];
2003	    char *out3 = data[4];
2004	
2005	    npy_intp in1_stride = strides[0];
2006	    npy_intp in2_stride = strides[1];
2007	    npy_intp out1_stride = strides[2];
2008	    npy_intp out2_stride = strides[3];
2009	    npy_intp out3_stride = strides[4];
2010	
2011	    npy_string_allocator *allocators[5] = {};
2012	    NpyString_acquire_allocators(5, context->descriptors, allocators);
2013	    npy_string_allocator *in1allocator = allocators[0];
2014	    npy_string_allocator *in2allocator = allocators[1];
2015	    npy_string_allocator *out1allocator = allocators[2];
2016	    npy_string_allocator *out2allocator = allocators[3];
2017	    npy_string_allocator *out3allocator = allocators[4];
2018	
2019	    PyArray_StringDTypeObject *nadescr = stringdtype_effective_na_descr(
2020	            context->method->nin, context->descriptors);
2021	    int has_string_na = nadescr->has_string_na;
2022	    const npy_static_string *default_string = &nadescr->default_string;
2023	
2024	    while (N--) {
2025	        const npy_packed_static_string *i1ps = (npy_packed_static_string *)in1;
2026	        npy_static_string i1s = {0, NULL};
2027	        const npy_packed_static_string *i2ps = (npy_packed_static_string *)in2;
2028	        npy_static_string i2s = {0, NULL};
2029	
2030	        int i1_isnull = NpyString_load(in1allocator, i1ps, &i1s);
2031	        int i2_isnull = NpyString_load(in2allocator, i2ps, &i2s);
2032	
2033	        if (i1_isnull == -1 || i2_isnull == -1) {
2034	            npy_gil_error(PyExc_MemoryError, "Failed to load string in %s",
2035	                          ((PyUFuncObject *)context->caller)->name);
2036	            goto fail;
2037	        }
2038	        else if (NPY_UNLIKELY(i1_isnull || i2_isnull)) {
2039	            if (!has_string_na) {
2040	                npy_gil_error(PyExc_ValueError,
2041	                              "Null values are not supported in %s",
2042	                              ((PyUFuncObject *)context->caller)->name);
2043	                goto fail;
2044	            }
2045	            else {
2046	                if (i1_isnull) {
2047	                    i1s = *default_string;
2048	                }
2049	                if (i2_isnull) {
2050	                    i2s = *default_string;
2051	                }
2052	            }
2053	        }
2054	
2055	        if (i2s.size == 0) {
2056	            npy_gil_error(PyExc_ValueError, "empty separator");
2057	            goto fail;
2058	        }
2059	
2060	        npy_intp idx = fastsearch((char *)i1s.buf, i1s.size, (char *)i2s.buf, i2s.size, -1,
2061	                                  fastsearch_direction);
2062	
2063	        npy_intp out1_size, out2_size, out3_size;
2064	
2065	        if (idx == -1) {
2066	            if (startposition == STARTPOSITION::FRONT) {
2067	                out1_size = i1s.size;
2068	                out2_size = out3_size = 0;
2069	            }
2070	            else {
2071	                out1_size = out2_size = 0;
2072	                out3_size = i1s.size;
2073	            }
2074	        }
2075	        else {
2076	            out1_size = idx;
2077	            out2_size = i2s.size;
2078	            out3_size = i1s.size - out2_size - out1_size;
2079	        }
2080	
2081	        npy_packed_static_string *o1ps = (npy_packed_static_string *)out1;
2082	        npy_static_string o1s = {0, NULL};
2083	        npy_packed_static_string *o2ps = (npy_packed_static_string *)out2;
2084	        npy_static_string o2s = {0, NULL};
2085	        npy_packed_static_string *o3ps = (npy_packed_static_string *)out3;
2086	        npy_static_string o3s = {0, NULL};
2087	
2088	        if (load_new_string(o1ps, &o1s, out1_size, out1allocator,
2089	                            ((PyUFuncObject *)context->caller)->name) == -1) {
2090	            goto fail;
2091	        }
2092	        if (load_new_string(o2ps, &o2s, out2_size, out2allocator,
2093	                            ((PyUFuncObject *)context->caller)->name) == -1) {
2094	            goto fail;
2095	        }
2096	        if (load_new_string(o3ps, &o3s, out3_size, out3allocator,
2097	                            ((PyUFuncObject *)context->caller)->name) == -1) {
2098	            goto fail;
2099	        }
2100	
2101	        if (idx == -1) {
2102	            if (startposition == STARTPOSITION::FRONT) {
2103	                memcpy((char *)o1s.buf, i1s.buf, out1_size);
2104	            }
2105	            else {
2106	                memcpy((char *)o3s.buf, i1s.buf, out3_size);
2107	            }
2108	        }
2109	        else {
2110	            memcpy((char *)o1s.buf, i1s.buf, out1_size);
2111	            memcpy((char *)o2s.buf, i2s.buf, out2_size);
2112	            memcpy((char *)o3s.buf, i1s.buf + out1_size + out2_size, out3_size);
2113	        }
2114	
2115	        in1 += in1_stride;
2116	        in2 += in2_stride;
2117	        out1 += out1_stride;
2118	        out2 += out2_stride;
2119	        out3 += out3_stride;
2120	    }
2121	
2122	    NpyString_release_allocators(5, allocators);
2123	    return 0;
2124	
2125	  fail:
2126	
2127	    NpyString_release_allocators(5, allocators);
2128	    return -1;
2129	}
