2131	NPY_NO_EXPORT int
2132	string_inputs_promoter(
2133	        PyObject *ufunc_obj, PyArray_DTypeMeta *const op_dtypes[],
2134	        PyArray_DTypeMeta *const signature[],
2135	        PyArray_DTypeMeta *new_op_dtypes[],
2136	        PyArray_DTypeMeta *final_dtype,
2137	        PyArray_DTypeMeta *result_dtype)
2138	{
2139	    PyUFuncObject *ufunc = (PyUFuncObject *)ufunc_obj;
2140	    /* set all input operands to final_dtype */
2141	    for (int i = 0; i < ufunc->nin; i++) {
2142	        PyArray_DTypeMeta *tmp = final_dtype;
2143	        if (signature[i]) {
2144	            tmp = signature[i]; /* never replace a fixed one. */
2145	        }
2146	        Py_INCREF(tmp);
2147	        new_op_dtypes[i] = tmp;
2148	    }
2149	    /* don't touch output dtypes if they are set */
2150	    for (int i = ufunc->nin; i < ufunc->nargs; i++) {
2151	        if (op_dtypes[i] != NULL) {
2152	            Py_INCREF(op_dtypes[i]);
2153	            new_op_dtypes[i] = op_dtypes[i];
2154	        }
2155	        else {
2156	            Py_INCREF(result_dtype);
2157	            new_op_dtypes[i] = result_dtype;
2158	        }
2159	    }
2160	
2161	    return 0;
2162	}
