2164	static int
2165	slice_promoter(PyObject *NPY_UNUSED(ufunc),
2166	        PyArray_DTypeMeta *const op_dtypes[], PyArray_DTypeMeta *const signature[],
2167	        PyArray_DTypeMeta *new_op_dtypes[])
