        PyArray_Descr *const given_descrs[],
        PyArray_Descr *loop_descrs[], npy_intp *NPY_UNUSED(view_offset))
{
    if (stringdtype_common_na_coerce(
                method->nin, given_descrs, NULL, NULL) == -1) {
